let playerX = 0; // initialize player's x position
let playerY = 0; // initialize player's y position

// setInterval function to create the game loop
setInterval(function() {
  // calculate distance traveled since last frame
  let deltaTime = Math.min(1, performance.now() - lastFrameTime);
  let dx = (playerX - lastPlayerX) * deltaTime;
  let dy = (playerY - lastPlayerY) * deltaTime;

  // update player's position based on distance traveled
  playerX += dx;
  playerY += dy;

  // set last frame time to current time for next iteration
  lastFrameTime = performance.now();
}, 1000 / 60); // 60 frames per second